// `polling` is true if a poll is in flight OR a poll completed within the
// last 2× the configured interval (i.e. the scheduler is still ticking).
const pollIntervalMs = Number(env.get('SFTP_POLL_INTERVAL_SECONDS') || 60) * 1000;
const lastPoll = flow.get('last_poll_ms');
const inflight = flow.get('poll_inflight') === true;
const recently = lastPoll && (Date.now() - lastPoll) < (2 * pollIntervalMs);
msg.payload = {
    status: 'ok',
    service: 'sftp-ingestion-service',
    polling: inflight || !!recently
};
msg.headers = { 'Content-Type': 'application/json' };
msg.statusCode = 200;
return msg;

const m = global.get('metrics') || {};

function emitCounter(name, help, samples) {
    let out = '# HELP ' + name + ' ' + help + '\n';
    out += '# TYPE ' + name + ' counter\n';
    if (samples.length === 0) {
        out += name + ' 0\n';
        return out;
    }
    for (const [labels, v] of samples) {
        const ls = Object.entries(labels).map(([k, vv]) => k + '="' + vv + '"').join(',');
        out += name + (ls ? '{' + ls + '}' : '') + ' ' + v + '\n';
    }
    return out;
}

let body = '';

const files = m.facis_sftp_files_ingested_total || {};
body += emitCounter('facis_sftp_files_ingested_total',
    'Total files successfully ingested via SFTP',
    Object.entries(files).map(([extension, v]) => [{ extension }, v]));

body += emitCounter('facis_sftp_records_published_total',
    'Total records published to Kafka from SFTP files',
    [[{}, m.facis_sftp_records_published_total || 0]]);

body += emitCounter('facis_sftp_poll_errors_total',
    'Total SFTP poll cycle errors',
    [[{}, m.facis_sftp_poll_errors_total || 0]]);

const dlq = m.facis_sftp_dlq_total || {};
body += emitCounter('facis_sftp_dlq_total',
    'Total messages routed to the SFTP DLQ topic',
    Object.entries(dlq).map(([error_type, v]) => [{ error_type }, v]));

// Histogram
const h = m.facis_sftp_poll_duration_seconds || { buckets: {}, sum: 0, count: 0 };
body += '# HELP facis_sftp_poll_duration_seconds Duration of each SFTP poll cycle\n';
body += '# TYPE facis_sftp_poll_duration_seconds histogram\n';
for (const b of [0.1, 0.5, 1, 5, 10, 30, 60]) {
    body += 'facis_sftp_poll_duration_seconds_bucket{le="' + b + '"} ' + (h.buckets[b] || 0) + '\n';
}
body += 'facis_sftp_poll_duration_seconds_bucket{le="+Inf"} ' + h.count + '\n';
body += 'facis_sftp_poll_duration_seconds_sum ' + h.sum + '\n';
body += 'facis_sftp_poll_duration_seconds_count ' + h.count + '\n';

msg.payload = body;
msg.headers = { 'Content-Type': 'text/plain; version=0.0.4' };
msg.statusCode = 200;
return msg;

const dlq = {
    error_type: 'uncaught',
    error_message: msg.error ? (msg.error.message || String(msg.error)) : 'unknown error',
    error_timestamp: new Date().toISOString(),
    filename: null,
    source_topic: null
};
return { payload: dlq };
